+        kind: "bundle",
+        version: bundle.version,
+        hash,
+        updatedAt: new Date().toISOString(),
+      };
+      manifest = upsertManifestEntry(manifest, entry);
+      writeManifest(targetRoot, manifest);
+
+      if (shouldOutputJson(options)) {
